const items = $input.all();
const coachData = $node["Read Coaches Tab"].first().json;
const overrideNotes = $node["Set Coach ID"].first().json.override_run_notes;

for (const item of items) {
  let text = item.json.text || item.json.body || JSON.stringify(item.json);

  // PII Redaction - Phone numbers
  text = text.replace(/(\+?1[-\.\s]?)?\(?\d{3}\)?[-\.\s]?\d{3}[-\.\s]?\d{4}/g, '[PHONE REDACTED]');

  // PII Redaction - Street addresses
  text = text.replace(/\d{1,5}\s+[\w\s]{2,30}(?:Street|St|Avenue|Ave|Road|Rd|Boulevard|Blvd|Drive|Dr|Lane|Ln|Court|Ct|Way|Place|Pl)\.?(?:\s*,?\s*(?:Apt|Suite|Ste|Unit|#)\s*\w+)?/gi, '[ADDRESS REDACTED]');

  // Normalize multiple blank lines
  text = text.replace(/\n{3,}/g, '\n\n').trim();

  item.json.cleaned_doc_content = text;
  item.json.coach_id = coachData.coach_id;
  item.json.coach_name = coachData.coach_name;
  item.json.coach_email = coachData.coach_email || '';
  item.json.doc_url = coachData.doc_url;
  item.json.run_notes = overrideNotes || coachData.run_notes || '';
}

return items;

const docItem = $node["Normalize and Redact PII"].first().json;
const clusterItems = $node["Read Cluster Library"].all();

// Build existing clusters summary
const existingClusters = clusterItems
  .filter(item => item.json.canonical_cluster_name)
  .map(item => ({
    canonical_cluster_name: item.json.canonical_cluster_name || '',
    definition: item.json.definition || '',
    common_symptoms: item.json.common_symptoms || '',
    times_seen: item.json.times_seen || 0
  }));

const existingClustersText = existingClusters.length > 0
  ? JSON.stringify(existingClusters, null, 2)
  : 'No existing clusters yet. All clusters from this analysis will be new.';

const systemPrompt = `You are an expert ICP (Ideal Client Profile) analyst specializing in online fitness coaching businesses.

You analyze coach questionnaire responses to identify problem clusters, score the ICP, build a tier list, and provide messaging guidance.

CRITICAL RULES:
1. Return ONLY valid JSON. No markdown code fences, no explanation text outside JSON.
2. Base problem clusters ONLY on the "Prospect Complaints (Voice of Prospect)" section.
3. Generate exactly 2-3 problem clusters.
4. All 5 ICP scoring factors MUST be filled (1-5 each). Emphasize Reachability, Willingness to Pay, and Urgency in writeups.
5. overall_stars = simple average of the 5 factor scores, rounded to nearest 0.5.
6. If required sections are weak or missing, set needs_followup=true and generate 8-12 follow-up questions.
7. For Numbers section, use buckets to estimate LTV. If missing, estimate conservatively and label as estimate.
8. Evidence quotes must be SHORT excerpts pulled directly from the document text.
9. Content themes should be 5-10 themes. NO hooks, scripts, calendars, or DM scripts.
10. Messaging dos/donts should be PRINCIPLES only, not copy.

EXPECTED QUESTIONNAIRE HEADINGS (handle minor variations):
- Coach Overview
- Target Client
- Prospect Complaints (Voice of Prospect)
- Desired Outcomes
- Objections
- Offer
- Proof
- Acquisition
- Numbers (Optional: price bucket, program length, capacity)

NUMBERS BUCKETS:
- Total program price bucket: <$300, $300-$750, $750-$1500, $1500+
- Program length/retention bucket: 4w, 8w, 12w, 6mo, ongoing, unknown-estimate
- Capacity bucket: <10, 10-20, 20-40, 40+, unknown-estimate

LTV ESTIMATION:
- LTV = program price x estimated retention cycles
- If Numbers section is missing, mark estimated_ltv.value as "unknown" and assumptions as ["Numbers section not provided"]
- Potential LTV score (1-5) should reflect expansion/continuity signals in the doc

Your JSON response MUST conform to this EXACT schema (no extra fields, no missing fields):
{
  "coach_id": "string",
  "coach_name": "string",
  "summary": {
    "one_paragraph": "string",
    "key_insights": ["string", "..."]
  },
  "problem_clusters": [
    {
      "cluster_name": "string (short, clear)",
      "who_it_applies_to": "string",
      "root_cause": "string",
      "symptoms": ["string", "..."],
      "why_they_fail_currently": ["string", "..."],
      "what_they_want_instead": ["string", "..."],
      "evidence_quotes": ["string (2-4 short excerpts from the doc)"]
    }
  ],
  "icp_scoring": {
    "overall_stars": 1,
    "factors": [
      {
        "factor_name": "Reachability",
        "score_1_to_5": 1,
        "reasoning": "string (grounded in doc)",
        "evidence_quotes": ["string (1-2)"]
      },
      {
        "factor_name": "Willingness to Pay",
        "score_1_to_5": 1,
        "reasoning": "string",
        "evidence_quotes": ["string"]
      },
      {
        "factor_name": "Urgency / Pain Intensity",
        "score_1_to_5": 1,
        "reasoning": "string",
        "evidence_quotes": ["string"]
      },
      {
        "factor_name": "Retention Potential",
        "score_1_to_5": 1,
        "reasoning": "string",
        "evidence_quotes": ["string"]
      },
      {
        "factor_name": "Competition / Differentiation Difficulty",
        "score_1_to_5": 1,
        "reasoning": "string",
        "evidence_quotes": ["string"]
      }
    ]
  },
  "tier_list": [
    {
      "segment_or_cluster": "string",
      "stars_1_to_5": 1,
      "reachability_notes": "string",
      "willingness_to_pay_notes": "string",
      "urgency_notes": "string",
      "estimated_ltv": {
        "value": "string (dollar amount or unknown)",
        "assumptions": ["string"]
      },
      "potential_ltv_score_1_to_5": 1,
      "potential_ltv_rationale": "string"
    }
  ],
  "messaging_guidance": {
    "dos": ["string (principles only)", "..."],
    "donts": ["string (principles only)", "..."],
    "objections_to_address": [
      {
        "objection": "string",
        "principled_response": "string"
      }
    ],
    "content_themes": ["string (5-10 themes, NO hooks/scripts)"]
  },
  "followup_questions": ["string (8-12 if needed, empty array if not)"],
  "needs_followup": false
}`;

const userPrompt = `Analyze the following fitness coach questionnaire and produce the complete ICP analysis.

COACH ID: ${docItem.coach_id}
COACH NAME: ${docItem.coach_name}
RUN NOTES: ${docItem.run_notes || 'None'}

=== QUESTIONNAIRE CONTENT ===
${docItem.cleaned_doc_content}
=== END QUESTIONNAIRE ===

=== EXISTING CLUSTER LIBRARY (for matching - use lowercase normalization) ===
${existingClustersText}
=== END CLUSTER LIBRARY ===

Return ONLY the JSON object. No other text.`;

const requestBody = {
  model: "claude-sonnet-4-20250514",
  max_tokens: 8192,
  system: systemPrompt,
  messages: [
    {
      role: "user",
      content: userPrompt
    }
  ]
};

return [{
  json: {
    requestBody: requestBody,
    coach_id: docItem.coach_id,
    coach_name: docItem.coach_name,
    coach_email: docItem.coach_email,
    doc_url: docItem.doc_url,
    run_notes: docItem.run_notes,
    cleaned_doc_content: docItem.cleaned_doc_content
  }
}];

const items = $input.all();
const promptData = $node["Build Anthropic Prompt"].first().json;

for (const item of items) {
  // Check if the API call failed
  if (item.json.error || (!item.json.content && !item.json.id)) {
    item.json.llm_error = true;
    item.json.error_message = item.json.error?.message || item.json.message || 'No content in API response';
    item.json.status = 'ERROR';
    item.json.coach_id = promptData.coach_id;
    item.json.coach_name = promptData.coach_name;
    continue;
  }

  // Extract text content from Anthropic response
  let rawText = '';
  if (Array.isArray(item.json.content)) {
    rawText = item.json.content
      .filter(block => block.type === 'text')
      .map(block => block.text)
      .join('');
  } else if (typeof item.json.content === 'string') {
    rawText = item.json.content;
  }

  // Strip accidental markdown code fences
  rawText = rawText.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();

  // Parse JSON
  let analysis;
  try {
    analysis = JSON.parse(rawText);
  } catch (e) {
    item.json.llm_error = true;
    item.json.error_message = `JSON parse error: ${e.message}. Raw response starts with: ${rawText.substring(0, 300)}`;
    item.json.status = 'ERROR';
    item.json.coach_id = promptData.coach_id;
    item.json.coach_name = promptData.coach_name;
    continue;
  }

  // Validate required top-level fields
  const requiredFields = ['problem_clusters', 'icp_scoring', 'tier_list', 'messaging_guidance'];
  const missingFields = requiredFields.filter(f => !analysis[f]);
  if (missingFields.length > 0) {
    item.json.llm_error = true;
    item.json.error_message = `Missing required fields in LLM response: ${missingFields.join(', ')}`;
    item.json.status = 'ERROR';
    item.json.coach_id = promptData.coach_id;
    item.json.coach_name = promptData.coach_name;
    continue;
  }

  if (!Array.isArray(analysis.problem_clusters) || analysis.problem_clusters.length === 0) {
    item.json.llm_error = true;
    item.json.error_message = 'problem_clusters must be a non-empty array';
    item.json.status = 'ERROR';
    item.json.coach_id = promptData.coach_id;
    item.json.coach_name = promptData.coach_name;
    continue;
  }

  // Success
  item.json.analysis = analysis;
  item.json.llm_error = false;
  item.json.coach_id = promptData.coach_id;
  item.json.coach_name = promptData.coach_name;
  item.json.coach_email = promptData.coach_email;
  item.json.doc_url = promptData.doc_url;
  item.json.run_notes = promptData.run_notes;
  item.json.needs_followup = analysis.needs_followup === true;
  item.json.status = analysis.needs_followup === true ? 'NEEDS_FOLLOWUP' : 'DONE';
}

return items;

const items = $input.all();
const now = new Date();
const dateStr = now.toISOString().split('T')[0];
const timeStr = now.toISOString().substring(11, 16).replace(':', '');
const timestamp = `${dateStr} ${timeStr}`;

for (const item of items) {
  const a = item.json.analysis;
  const s = a.summary || {};
  let r = '';

  // ===== HEADER =====
  r += '════════════════════════════════════════════════════════\n';
  r += 'INTERNAL ICP PROBLEM CLUSTER REPORT\n';
  r += '════════════════════════════════════════════════════════\n\n';
  r += `Coach: ${a.coach_name || item.json.coach_name} (${a.coach_id || item.json.coach_id})\n`;
  r += `Generated: ${timestamp}\n`;
  r += `Status: ${item.json.status}\n`;
  r += `Overall ICP Score: ${a.icp_scoring.overall_stars}/5 stars\n\n`;

  // ===== EXECUTIVE SUMMARY =====
  r += '────────────────────────────────────────────────────────\n';
  r += 'EXECUTIVE SUMMARY\n';
  r += '────────────────────────────────────────────────────────\n\n';
  r += `${s.one_paragraph || 'N/A'}\n\n`;
  if (s.key_insights && s.key_insights.length > 0) {
    r += 'Key Insights:\n';
    s.key_insights.forEach(insight => {
      r += `  • ${insight}\n`;
    });
    r += '\n';
  }

  // ===== PROBLEM CLUSTERS =====
  r += '────────────────────────────────────────────────────────\n';
  r += `PROBLEM CLUSTERS (${a.problem_clusters.length} identified)\n`;
  r += '────────────────────────────────────────────────────────\n\n';
  a.problem_clusters.forEach((cluster, i) => {
    r += `▶ CLUSTER ${i + 1}: ${cluster.cluster_name}\n`;
    r += `  Who it applies to: ${cluster.who_it_applies_to}\n`;
    r += `  Root cause: ${cluster.root_cause}\n\n`;
    if (cluster.symptoms && cluster.symptoms.length > 0) {
      r += '  Symptoms:\n';
      cluster.symptoms.forEach(s => { r += `    - ${s}\n`; });
      r += '\n';
    }
    if (cluster.why_they_fail_currently && cluster.why_they_fail_currently.length > 0) {
      r += '  Why they fail currently:\n';
      cluster.why_they_fail_currently.forEach(f => { r += `    - ${f}\n`; });
      r += '\n';
    }
    if (cluster.what_they_want_instead && cluster.what_they_want_instead.length > 0) {
      r += '  What they want instead:\n';
      cluster.what_they_want_instead.forEach(w => { r += `    - ${w}\n`; });
      r += '\n';
    }
    if (cluster.evidence_quotes && cluster.evidence_quotes.length > 0) {
      r += '  Evidence quotes:\n';
      cluster.evidence_quotes.forEach(q => { r += `    "${q}"\n`; });
      r += '\n';
    }
    r += '\n';
  });

  // ===== ICP SCORING =====
  r += '────────────────────────────────────────────────────────\n';
  r += 'ICP SCORING (5-Factor Analysis)\n';
  r += '────────────────────────────────────────────────────────\n\n';
  r += `Overall Stars: ${'★'.repeat(Math.round(a.icp_scoring.overall_stars))}${'☆'.repeat(5 - Math.round(a.icp_scoring.overall_stars))} (${a.icp_scoring.overall_stars}/5)\n\n`;
  if (a.icp_scoring.factors && a.icp_scoring.factors.length > 0) {
    a.icp_scoring.factors.forEach(factor => {
      const emphasis = ['Reachability', 'Willingness to Pay', 'Urgency / Pain Intensity'].includes(factor.factor_name) ? ' ⬅ KEY FACTOR' : '';
      r += `  ${factor.factor_name}: ${factor.score_1_to_5}/5${emphasis}\n`;
      r += `    Reasoning: ${factor.reasoning}\n`;
      if (factor.evidence_quotes && factor.evidence_quotes.length > 0) {
        factor.evidence_quotes.forEach(q => { r += `    Evidence: "${q}"\n`; });
      }
      r += '\n';
    });
  }

  // ===== TIER LIST =====
  r += '────────────────────────────────────────────────────────\n';
  r += 'ICP TIER LIST\n';
  r += '────────────────────────────────────────────────────────\n\n';
  if (a.tier_list && a.tier_list.length > 0) {
    a.tier_list.forEach((tier, i) => {
      r += `  ${i + 1}. ${tier.segment_or_cluster} — ${'★'.repeat(tier.stars_1_to_5)}${'☆'.repeat(5 - tier.stars_1_to_5)}\n`;
      r += `     Reachability: ${tier.reachability_notes}\n`;
      r += `     Willingness to Pay: ${tier.willingness_to_pay_notes}\n`;
      r += `     Urgency: ${tier.urgency_notes}\n`;
      r += `     Estimated LTV: ${tier.estimated_ltv?.value || 'unknown'}\n`;
      if (tier.estimated_ltv?.assumptions && tier.estimated_ltv.assumptions.length > 0) {
        r += `     LTV Assumptions: ${tier.estimated_ltv.assumptions.join('; ')}\n`;
      }
      r += `     Potential LTV Score: ${tier.potential_ltv_score_1_to_5}/5\n`;
      r += `     Potential LTV Rationale: ${tier.potential_ltv_rationale}\n\n`;
    });
  }

  // ===== MESSAGING GUIDANCE =====
  r += '────────────────────────────────────────────────────────\n';
  r += 'MESSAGING GUIDANCE\n';
  r += '────────────────────────────────────────────────────────\n\n';
  const mg = a.messaging_guidance || {};
  if (mg.dos && mg.dos.length > 0) {
    r += '  DO:\n';
    mg.dos.forEach(d => { r += `    ✓ ${d}\n`; });
    r += '\n';
  }
  if (mg.donts && mg.donts.length > 0) {
    r += '  DON\'T:\n';
    mg.donts.forEach(d => { r += `    ✗ ${d}\n`; });
    r += '\n';
  }
  if (mg.objections_to_address && mg.objections_to_address.length > 0) {
    r += '  OBJECTIONS TO ADDRESS:\n';
    mg.objections_to_address.forEach(obj => {
      r += `    Objection: "${obj.objection}"\n`;
      r += `    Principled Response: ${obj.principled_response}\n\n`;
    });
  }
  if (mg.content_themes && mg.content_themes.length > 0) {
    r += '  CONTENT THEMES:\n';
    mg.content_themes.forEach((t, i) => { r += `    ${i + 1}. ${t}\n`; });
    r += '\n';
  }

  // ===== VIDEO TALKING POINTS =====
  r += '────────────────────────────────────────────────────────\n';
  r += 'VIDEO TALKING POINTS\n';
  r += '────────────────────────────────────────────────────────\n\n';
  r += `  • This coach targets: ${a.problem_clusters[0]?.who_it_applies_to || 'See clusters above'}\n`;
  r += `  • Top cluster: "${a.problem_clusters[0]?.cluster_name || 'N/A'}" — ${a.problem_clusters[0]?.root_cause || ''}\n`;
  r += `  • ICP overall score: ${a.icp_scoring.overall_stars}/5\n`;
  const topFactors = (a.icp_scoring.factors || []).filter(f => ['Reachability', 'Willingness to Pay', 'Urgency / Pain Intensity'].includes(f.factor_name));
  topFactors.forEach(f => {
    r += `  • ${f.factor_name}: ${f.score_1_to_5}/5 — ${f.reasoning.substring(0, 100)}...\n`;
  });
  if (a.tier_list && a.tier_list.length > 0) {
    r += `  • Best segment: ${a.tier_list[0].segment_or_cluster} (${a.tier_list[0].stars_1_to_5} stars)\n`;
  }
  r += `  • Key messaging themes: ${(mg.content_themes || []).slice(0, 3).join(', ')}\n`;
  r += '\n';

  // ===== FOLLOW-UP QUESTIONS =====
  if (a.followup_questions && a.followup_questions.length > 0) {
    r += '────────────────────────────────────────────────────────\n';
    r += 'FOLLOW-UP QUESTIONS\n';
    r += '────────────────────────────────────────────────────────\n\n';
    a.followup_questions.forEach((q, i) => {
      r += `  ${i + 1}. ${q}\n`;
    });
    r += '\n';
  }

  r += '════════════════════════════════════════════════════════\n';
  r += 'END OF INTERNAL REPORT\n';
  r += '════════════════════════════════════════════════════════\n';

  item.json.internal_report_text = r;
  item.json.report_timestamp = timestamp;
}

return items;

const items = $input.all();

for (const item of items) {
  const a = item.json.analysis;
  const s = a.summary || {};
  const timestamp = item.json.report_timestamp;
  let r = '';

  // ===== HEADER =====
  r += '════════════════════════════════════════════════════════\n';
  r += 'YOUR ICP PROBLEM CLUSTER REPORT\n';
  r += '════════════════════════════════════════════════════════\n\n';
  r += `Prepared for: ${a.coach_name || item.json.coach_name}\n`;
  r += `Date: ${timestamp}\n`;
  r += `Overall ICP Score: ${'★'.repeat(Math.round(a.icp_scoring.overall_stars))}${'☆'.repeat(5 - Math.round(a.icp_scoring.overall_stars))} (${a.icp_scoring.overall_stars}/5)\n\n`;

  // ===== KEY INSIGHTS =====
  r += '────────────────────────────────────────────────────────\n';
  r += 'KEY INSIGHTS SUMMARY\n';
  r += '────────────────────────────────────────────────────────\n\n';
  r += `${s.one_paragraph || 'N/A'}\n\n`;
  if (s.key_insights && s.key_insights.length > 0) {
    s.key_insights.forEach(insight => {
      r += `  • ${insight}\n`;
    });
    r += '\n';
  }

  // ===== PROBLEM CLUSTERS =====
  r += '────────────────────────────────────────────────────────\n';
  r += 'YOUR CLIENT PROBLEM CLUSTERS\n';
  r += '────────────────────────────────────────────────────────\n\n';
  r += 'These are the core problem patterns we identified in how your prospects describe their challenges:\n\n';
  a.problem_clusters.forEach((cluster, i) => {
    r += `▶ CLUSTER ${i + 1}: ${cluster.cluster_name}\n\n`;
    r += `  Who this applies to: ${cluster.who_it_applies_to}\n`;
    r += `  Root cause: ${cluster.root_cause}\n\n`;
    if (cluster.symptoms && cluster.symptoms.length > 0) {
      r += '  What they experience:\n';
      cluster.symptoms.forEach(s => { r += `    - ${s}\n`; });
      r += '\n';
    }
    if (cluster.why_they_fail_currently && cluster.why_they_fail_currently.length > 0) {
      r += '  Why current solutions fail them:\n';
      cluster.why_they_fail_currently.forEach(f => { r += `    - ${f}\n`; });
      r += '\n';
    }
    if (cluster.what_they_want_instead && cluster.what_they_want_instead.length > 0) {
      r += '  What they actually want:\n';
      cluster.what_they_want_instead.forEach(w => { r += `    - ${w}\n`; });
      r += '\n';
    }
    if (cluster.evidence_quotes && cluster.evidence_quotes.length > 0) {
      r += '  From your questionnaire:\n';
      cluster.evidence_quotes.forEach(q => { r += `    "${q}"\n`; });
      r += '\n';
    }
    r += '\n';
  });

  // ===== ICP SCORING =====
  r += '────────────────────────────────────────────────────────\n';
  r += 'YOUR ICP SCORE BREAKDOWN\n';
  r += '────────────────────────────────────────────────────────\n\n';
  r += `Overall: ${'★'.repeat(Math.round(a.icp_scoring.overall_stars))}${'☆'.repeat(5 - Math.round(a.icp_scoring.overall_stars))} (${a.icp_scoring.overall_stars}/5)\n\n`;
  if (a.icp_scoring.factors && a.icp_scoring.factors.length > 0) {
    a.icp_scoring.factors.forEach(factor => {
      r += `  ${factor.factor_name}: ${'★'.repeat(factor.score_1_to_5)}${'☆'.repeat(5 - factor.score_1_to_5)} (${factor.score_1_to_5}/5)\n`;
      r += `    ${factor.reasoning}\n\n`;
    });
  }

  // ===== RECOMMENDED BEST-FIT =====
  r += '────────────────────────────────────────────────────────\n';
  r += 'RECOMMENDED BEST-FIT SEGMENT\n';
  r += '────────────────────────────────────────────────────────\n\n';
  if (a.tier_list && a.tier_list.length > 0) {
    const best = a.tier_list.reduce((a, b) => a.stars_1_to_5 >= b.stars_1_to_5 ? a : b);
    r += `  Recommended: ${best.segment_or_cluster} (${'★'.repeat(best.stars_1_to_5)} ${best.stars_1_to_5}/5)\n\n`;
    r += `  Why this segment:\n`;
    r += `    - Reachability: ${best.reachability_notes}\n`;
    r += `    - Willingness to Pay: ${best.willingness_to_pay_notes}\n`;
    r += `    - Urgency: ${best.urgency_notes}\n\n`;
    r += '  Full tier comparison:\n';
    a.tier_list.forEach((tier, i) => {
      r += `    ${i + 1}. ${tier.segment_or_cluster} — ${'★'.repeat(tier.stars_1_to_5)} (${tier.stars_1_to_5}/5)\n`;
    });
    r += '\n';
  }

  // ===== MESSAGING DO'S/DON'TS =====
  r += '────────────────────────────────────────────────────────\n';
  r += 'MESSAGING PRINCIPLES\n';
  r += '────────────────────────────────────────────────────────\n\n';
  const mg = a.messaging_guidance || {};
  if (mg.dos && mg.dos.length > 0) {
    r += '  DO:\n';
    mg.dos.forEach(d => { r += `    ✓ ${d}\n`; });
    r += '\n';
  }
  if (mg.donts && mg.donts.length > 0) {
    r += '  DON\'T:\n';
    mg.donts.forEach(d => { r += `    ✗ ${d}\n`; });
    r += '\n';
  }

  // ===== CONTENT THEMES =====
  if (mg.content_themes && mg.content_themes.length > 0) {
    r += '────────────────────────────────────────────────────────\n';
    r += 'CONTENT THEMES\n';
    r += '────────────────────────────────────────────────────────\n\n';
    r += 'These are themes you can build content around (no scripts — just directions):\n\n';
    mg.content_themes.forEach((t, i) => { r += `  ${i + 1}. ${t}\n`; });
