  }

  // ===== FOLLOW-UP QUESTIONS =====
  if (a.followup_questions && a.followup_questions.length > 0) {
    r += '────────────────────────────────────────────────────────\n';
    r += 'FOLLOW-UP QUESTIONS\n';
    r += '────────────────────────────────────────────────────────\n\n';
    r += 'To strengthen our analysis, please consider addressing these:\n\n';
    a.followup_questions.forEach((q, i) => {
      r += `  ${i + 1}. ${q}\n`;
    });
    r += '\n';
  }

  r += '════════════════════════════════════════════════════════\n';
  r += 'END OF REPORT\n';
  r += '════════════════════════════════════════════════════════\n';

  item.json.coach_report_text = r;
}

