const items = $input.all();
const analysis = items[0].json.analysis;
const existingClusters = $node["Read Cluster Library"].all().map(i => i.json);
const now = new Date().toISOString();

const normalize = (name) => (name || '').toLowerCase().replace(/[^a-z0-9\s]/g, '').trim();

const outputItems = [];

for (const cluster of (analysis.problem_clusters || [])) {
  const normalizedName = normalize(cluster.cluster_name);

  // Try to match existing
  const match = existingClusters.find(existing => {
    const existingNorm = normalize(existing.canonical_cluster_name);
    return existingNorm === normalizedName || existingNorm.includes(normalizedName) || normalizedName.includes(existingNorm);
  });

  if (match) {
    // Update existing: increment times_seen
    outputItems.push({
      json: {
        canonical_cluster_name: match.canonical_cluster_name,
        definition: match.definition,
        common_symptoms: match.common_symptoms,
        typical_objections: match.typical_objections,
        created_at: match.created_at,
        times_seen: (parseInt(match.times_seen) || 0) + 1
      }
    });
  } else {
    // New cluster
    const symptoms = (cluster.symptoms || []).join(', ');
    const objections = (analysis.messaging_guidance?.objections_to_address || [])
      .map(o => o.objection).join(', ');

    outputItems.push({
      json: {
        canonical_cluster_name: cluster.cluster_name,
        definition: cluster.root_cause || '',
        common_symptoms: symptoms,
        typical_objections: objections,
        created_at: now,
        times_seen: 1
      }
    });
  }
}

return outputItems.length > 0 ? outputItems : [{ json: { _skip: true } }];
